mapper.select:
SELECT id, designer_id, name, phone, memo, created_at, updated_at
FROM customers
WHERE id = #{customerId}
AND designer_id = #{designerId}

mapper.update:
UPDATE customers

    name = #{dto.name},
    phone = #{dto.phone},
    memo = #{dto.memo},

WHERE id = #{customerId}
AND designer_id = #{designerId}

mapper.delete:
DELETE FROM customers
WHERE id = #{customerId}
AND designer_id = #{designerId}
